41: func pluginsNames(p *configv1.Plugins) []string {
42: 	if p == nil {
43: 		return nil
44: 	}
45: 	extensions := []configv1.PluginSet{
46: 		p.MultiPoint,
47: 		p.PreFilter,
48: 		p.Filter,
49: 		p.PostFilter,
50: 		p.Reserve,
51: 		p.PreScore,
52: 		p.Score,
53: 		p.PreBind,
54: 		p.Bind,
55: 		p.PostBind,
56: 		p.Permit,
57: 		p.PreEnqueue,
58: 		p.QueueSort,
59: 	}
60: 	n := sets.New[string]()
61: 	for _, e := range extensions {
62: 		for _, pg := range e.Enabled {
63: 			n.Insert(pg.Name)
64: 		}
65: 	}
66: 	return sets.List(n)
67: }
